// src/nodes/outputNode.js
import { useState } from 'react';
import { Handle, Position } from 'reactflow';
import './node.css';



export const OutputNode = ({ id, data }) => {
  const [currName, setCurrName] = useState(data?.outputName || `output_${id.slice(-4)}`);
  const [outputType, setOutputType] = useState(data?.outputType || 'Text');

  const handleNameChange = (e) => {
    setCurrName(e.target.value);
    data.outputName = e.target.value;
    data.label = e.target.value;
  };

  const handleTypeChange = (e) => {
    setOutputType(e.target.value);
    data.outputType = e.target.value;
  };

  return (
    <div className="vs-node">
      <Handle type="target" position={Position.Left} id="value" />
      <div className="vs-node-header">{data?.label || "Output"}</div>
      <div className="vs-node-body">
        <label>
          Name:
          <input
            type="text"
            value={currName}
            onChange={handleNameChange}
            placeholder="Output name"
          />
        </label>
        <label>
          Type:
          <select value={outputType} onChange={handleTypeChange}>
            <option value="Text">Text</option>
            <option value="Image">Image</option>
          </select>
        </label>
      </div>
    </div>
  );
};
